struct MinHeap {
    heap: Array<State>
}

impl MinHeap {
    fn new() -> MinHeap {
        MinHeap(Array.new([]))
    }

    fn size(&self) -> Int {
        self.heap.len
    }

    fn peek(&self) -> Option<State> {
        self.size() > 0 ? Some(self.heap[0]) : None
    }

    fn push(&mut self, state: State) {
        self.heap.push(state)
        self.siftUp(self.heap.len - 1)
    }

    fn pop(&mut self) -> Option<State> {
        guard self.size() > 0
        state := self.heap[0]
        self.heap[0] = self.heap.pop().unwrap()
        self.siftDown(0)
        Some(state)
    end

    fn siftUp(&mut self, i: Int) {
        var current = i
        while current > 0 {
            parent = (current - 1) / 2
            if self.heap[current].time < self.heap[parent].time ||
               (self.heap[current].time == self.heap[parent].time && self.heap[current].neg_color < self.heap[parent].neg_color)
            {
                self.heap.swap(current, parent)
                current = parent
            } else {
                break
            }
        }
    }

    fn siftDown(&mut self, i: Int) {
        var current = i
        while true {
            left = 2 * current + 1
            right = 2 * current + 2
            smallest = current

            // Check left child
            if left < self.heap.len {
                if self.heap[left].time < self.heap[smallest].time ||
                   (self.heap[left].time == self.heap[smallest].time && self.heap[left].neg_color < self.heap[smallest].neg_color)
