                   (self.heap[right].time == self.heap[smallest].time && self.heap[right].neg_color < self.heap[smallest].neg_color)
                {
                    smallest = right
                }
            }

            if smallest != current {
                self.heap.swap(current, smallest)
                current = smallest
            } else {
                break
            }
        }
    }
}


