#include <algorithm>
#include <vector>
#include <queue>
#include <tuple>

// Define the state for the Priority Queue: (time, -color, r, c)
// We use negative color because std::priority_queue is a max-heap, and we want to prioritize minimum time, 
// and then maximum color (i.e., minimum -color) in case of time ties.
using State = std::tuple<int64_t, int64_t, int64_t, int64_t>;

// Custom comparator for the priority queue
struct CompareState {
    bool operator()(const State& a, const State& b) {
        // Compare times (min-heap on time)
        if (std::get<0>(a) != std::get<0>(b)) {
            return std::get<0>(a) > std::get<0>(b); // True if a has higher time (should come later)
        }
        // If times are equal, compare negated colors (min-heap on -color, which means max-heap on color)
        return std::get<1>(a) > std::get<1>(b); // True if a has smaller negated color (i.e., larger color, should come later in a max-heap setup for min-heap behavior on the second element)
    }
};


std::vector<std::vector<int64_t>> solve(int64_t n, int64_t m, std::vector<std::vector<int64_t>>& sources) {
    // Initialize distance/time array T (stores minimum time)
    // Use a large number for infinity, N*M + 1 is sufficient since max time is N*M - 1
    const int64_t INF_TIME = n * m + 1;
    std::vector<std::vector<int64_t>> T(n, std::vector<int64_t>(m, INF_TIME));

    // Initialize color array C (stores final color)
    std::vector<std::vector<int64_t>> C(n, std::vector<int64_t>(m, 0));

    // Min-Priority Queue: Stores (time, -color, r, c)
    std::priority_queue<State, std::vector<State>, CompareState> pq;

    // 1. Initialization from sources
    for (const auto& source : sources) {
        int64_t r = source[0];
        int64_t c = source[1];
        int64_t color = source[2];

        // Since sources are guaranteed unique, we don't need complex initialization checks here
        T[r][c] = 0;
        C[r][c] = color;

        // Push (time=0, -color, r, c)
        pq.push({0, -color, r, c});
    }

    int64_t dr[] = {-1, 1, 0, 0};
    int64_t dc[] = {0, 0, -1, 1};

    // 2. Dijkstra-like Expansion
    while (!pq.empty()) {
        auto [t, neg_c, r, c_coord] = pq.top();
        pq.pop();

        int64_t color = -neg_c;

        // Check for stale entries
        // If the extracted time is worse than the best known time, skip.
        if (t > T[r][c_coord]) {
            continue;
        }
        // If time is equal, but the extracted color is worse than the best known color, skip.
        if (t == T[r][c_coord] && color < C[r][c_coord]) {
            continue;
        }

        // Propagate to neighbors
        for (int i = 0; i < 4; ++i) {
            int64_t r_prime = r + dr[i];
            int64_t c_prime = c_coord + dc[i];

            // Check boundaries
            if (r_prime >= 0 && r_prime < n && c_prime >= 0 && c_prime < m) {
                int64_t t_prime = t + 1;
                int64_t c_prime_color = color;

                // Relaxation logic

                // Case 1: Strictly faster path found
                if (t_prime < T[r_prime][c_prime]) {
                    T[r_prime][c_prime] = t_prime;
                    C[r_prime][c_prime] = c_prime_color;
                    pq.push({t_prime, -c_prime_color, r_prime, c_prime});
